// src/components/ui/KkotiumSymbol.tsx
// KKOTIUM brand symbols
// WhiteTulip: white silhouette version for use on red background
// ColorSymbol: full color official SVG

interface Props {
  size?: number;
  className?: string;
}

// ── White tulip silhouette — for red background ─────────────────────────────
// Matches the white PNG: two smiling flower characters with wavy stems
export function KkotiumWhiteTulip({ size = 32, className = '' }: Props) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      viewBox="0 0 100 100"
      className={className}
      aria-label="KKOTIUM"
    >
      {/* Left flower — daisy style */}
      {/* Petals */}
      <ellipse cx="22" cy="14" rx="5" ry="8" fill="white" transform="rotate(-30 22 14)" />
      <ellipse cx="22" cy="14" rx="5" ry="8" fill="white" transform="rotate(0 22 14)" />
      <ellipse cx="22" cy="14" rx="5" ry="8" fill="white" transform="rotate(30 22 14)" />
      <ellipse cx="22" cy="14" rx="5" ry="8" fill="white" transform="rotate(60 22 14)" />
      <ellipse cx="22" cy="14" rx="5" ry="8" fill="white" transform="rotate(90 22 14)" />
      <ellipse cx="22" cy="14" rx="5" ry="8" fill="white" transform="rotate(120 22 14)" />
      {/* Face center */}
      <circle cx="22" cy="14" r="5.5" fill="white" />
      {/* Eyes */}
      <circle cx="20" cy="13" r="0.9" fill="#e62310" />
      <circle cx="24" cy="13" r="0.9" fill="#e62310" />
      {/* Smile */}
      <path d="M19.5 15.5 Q22 17.5 24.5 15.5" stroke="#e62310" strokeWidth="0.8" fill="none" strokeLinecap="round" />

      {/* Right flower — tulip style */}
      {/* Petals */}
      <ellipse cx="78" cy="12" rx="7" ry="9" fill="white" />
      <ellipse cx="73" cy="14" rx="5" ry="8" fill="white" transform="rotate(-20 73 14)" />
      <ellipse cx="83" cy="14" rx="5" ry="8" fill="white" transform="rotate(20 83 14)" />
      {/* Face center */}
      <circle cx="78" cy="14" r="5" fill="white" />
      {/* Eyes */}
      <circle cx="76" cy="13" r="0.9" fill="#e62310" />
      <circle cx="80" cy="13" r="0.9" fill="#e62310" />
      {/* Smile */}
      <path d="M74.5 15.5 Q78 17.5 81.5 15.5" stroke="#e62310" strokeWidth="0.8" fill="none" strokeLinecap="round" />

      {/* Wavy connected stems */}
      {/* Left stem down */}
      <path
        d="M22 23 C20 30 24 36 22 43 C20 50 16 54 20 60 C22 64 28 65 28 72 C28 78 24 82 26 88"
        stroke="white" strokeWidth="3.5" fill="none" strokeLinecap="round"
      />
      {/* Right stem down */}
      <path
        d="M78 23 C80 30 76 36 78 43 C80 50 84 54 80 60 C78 64 72 65 72 72 C72 78 76 82 74 88"
        stroke="white" strokeWidth="3.5" fill="none" strokeLinecap="round"
      />
      {/* Connecting wave between stems — mid height */}
      <path
        d="M22 43 C28 40 35 46 40 43 C45 40 48 46 50 43 C52 40 55 46 60 43 C65 40 72 46 78 43"
        stroke="white" strokeWidth="3" fill="none" strokeLinecap="round"
      />
      {/* Left leaf */}
      <path d="M22 55 C14 50 10 44 15 40" stroke="white" strokeWidth="3" fill="none" strokeLinecap="round" />
      {/* Right leaf */}
      <path d="M78 55 C86 50 90 44 85 40" stroke="white" strokeWidth="3" fill="none" strokeLinecap="round" />
      {/* Root waves at bottom */}
      <path
        d="M10 88 C14 84 18 92 26 88 C34 84 38 92 50 88 C62 84 66 92 74 88 C82 84 86 92 90 88"
        stroke="white" strokeWidth="3" fill="none" strokeLinecap="round"
      />
    </svg>
  );
}

