// Badge wrapper for sidebar (red bg + white tulip)
export function KkotiumBadge({ size = 36, variant = 'color' }: { size?: number; variant?: 'color' | 'white-on-red' }) {
  if (variant === 'white-on-red') {
    return (
      <div
        style={{
          width: size,
          height: size,
          background: '#e62310',
          borderRadius: '12px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
        }}
      >
        <KkotiumWhiteTulip size={size * 0.72} />
      </div>
    );
  }
  return (
    <div
      style={{
        width: size,
        height: size,
        background: 'linear-gradient(135deg, #FFF0F5 0%, #FFE8EF 100%)',
        border: '1.5px solid #FFB3CC',
        borderRadius: '12px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: 0,
      }}
    >
      <KkotiumSymbol size={size * 0.78} />
    </div>
  );
}
